class Solution {
public:
    int findRowWithMaxOnes(int n, int m, vector<vector<int>>& mat) {
        int bestRow = -1;

        // Start from the top-right corner
        int i = 0;       // Row index
        int j = m - 1;   // Column index

        while (i < n && j >= 0) {
            if (mat[i][j] == 1) {
                // If we find a 1, record this row and move left to check for more 1s
                bestRow = i;
                j--;
            } else {
                // If we find a 0, move down to the next row
                i++;
            }
        }

        return bestRow;
    }
};

