/**
 * Finds the index of the row with the maximum number of 1s.
 * * @param {number[][]} mat - A 2D matrix containing only 0s and 1s.
 * @param {number} n - Number of rows in the matrix.
 * @param {number} m - Number of columns in the matrix.
 * @returns {number} - The index of the row with the maximum number of 1s, or -1.
 */
function findRowWithMaxOnes(n, m,mat) {
    let maxRowIndex = -1;
    let row = 0;
    let col = m - 1;

    // Start from the top-right corner
    while (row < n && col >= 0) {
        if (mat[row][col] === 1) {
            // We found a 1, update max row index and move left
            maxRowIndex = row;
            col--; 
        } else {
            // We found a 0, we can't get more 1s in this row, move down
            row++;
        }
    }

    return maxRowIndex;
}
